import*as Browser from"@hyperjump/browser";import{Validation}from"../experimental.js";import{toAbsoluteUri}from"../common.js";const id="https://json-schema.org/keyword/dynamicRef",compile=async(r,o)=>{var e=Browser.value(r),r=await Browser.get(r.document.baseUri,r);return await Validation.compile(r,o),e},interpret=(r,o,e)=>{if(r in e.dynamicAnchors)return Validation.interpret(e.dynamicAnchors[r],o,e);throw Error(`No dynamic anchor found for "${r}"`)},simpleApplicator=!0,plugin={beforeSchema(r,o,e){e.dynamicAnchors={...e.ast.metaData[toAbsoluteUri(r)].dynamicAnchors,...e.dynamicAnchors}},beforeKeyword(r,o,e,i){e.dynamicAnchors=i.dynamicAnchors},afterKeyword(){},afterSchema(){}};export default{id:id,compile:compile,interpret:interpret,simpleApplicator:simpleApplicator,plugin:plugin};